krpano.action:
cleardelayedcall(autohide_tip);
if(get(tip_id) EQ "h",
	tween(global.layer[h_tip].alpha, 1.0, 0.3);
	delayedcall(autohide_tip, 3, tween(global.layer[h_tip].alpha, 0.0, 0.5));
,
	tween(global.layer[v_tip].alpha, 1.0, 0.3);
	delayedcall(autohide_tip, 3, tween(global.layer[v_tip].alpha, 0.0, 0.5));
);
